import React, { useState, useEffect } from 'react';
import './CommandeForm.css';
import { jsPDF } from 'jspdf';
import html2canvas from 'html2canvas';

const CommandeForm = ({ selectedCommande, onSuccess, onCancel }) => {
  const [formData, setFormData] = useState({
    idCOM: '',
    codeCli: '',
    codeArt: '',
    dateCom: '',
    QteCom: ''
  });

  const [factureVisible, setFactureVisible] = useState(false);
  const [factureData, setFactureData] = useState(null);
  const [message, setMessage] = useState('');
  const [error, setError] = useState('');

  useEffect(() => {
    if (selectedCommande) {
      // Nettoyer la date pour garder uniquement la partie YYYY-MM-DD
      setFormData({
        ...selectedCommande,
        dateCom: selectedCommande.dateCom ? selectedCommande.dateCom.split('T')[0] : ''
      });
      setFactureVisible(false);
    } else {
      resetForm();
    }
  }, [selectedCommande]);

  // Validation : chiffres uniquement pour certains champs
  const validateForm = ({ idCOM, codeCli, codeArt, QteCom, dateCom }) => {
    const onlyDigits = /^[0-9]+$/;
    if (idCOM && !onlyDigits.test(idCOM)) return 'L\'ID Commande doit contenir uniquement des chiffres.';
    if (!onlyDigits.test(codeCli)) return 'Le code client doit contenir uniquement des chiffres.';
    if (!onlyDigits.test(codeArt)) return 'Le code article doit contenir uniquement des chiffres.';
    if (!onlyDigits.test(QteCom)) return 'La quantité doit contenir uniquement des chiffres.';
    if (!dateCom) return 'La date de commande est requise.';
    return null;
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };
 
  const resetForm = () => {
    setFormData({
      idCOM: '',
      codeCli: '',
      codeArt: '',
      dateCom: '',
      QteCom: ''
    });
    setFactureVisible(false);
    setFactureData(null);
    setMessage('');
    setError('');
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    setError('');
    setMessage('');

    const validationError = validateForm(formData);
    if (validationError) {
      setError(validationError);
      return;
    }

    const method = formData.idCOM ? 'PUT' : 'POST';
    const url = formData.idCOM
      ? `http://localhost:3001/commandes/${formData.idCOM}`
      : 'http://localhost:3001/commandes';

    try {
      const res = await fetch(url, {
        method,
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(formData)
      });

      if (!res.ok) {
        const text = await res.text();
        throw new Error(`Erreur ${res.status} : ${text}`);
      }

      setMessage(formData.idCOM ? 'Commande modifiée avec succès.' : 'Commande ajoutée avec succès.');
      resetForm();
      if (onSuccess) onSuccess();
    } catch (err) {
      setError(err.message);
    }
  };

  const handleDelete = async () => {
    const confirmDelete = window.confirm('Supprimer cette commande ?');
    if (!confirmDelete) return;

    try {
      const res = await fetch(`http://localhost:3001/commandes/${formData.idCOM}`, {
        method: 'DELETE'
      });

      if (!res.ok) {
        const text = await res.text();
        throw new Error(`Erreur ${res.status} : ${text}`);
      }

      setMessage('Commande supprimée avec succès.');
      resetForm();
      if (onSuccess) onSuccess();
    } catch (err) {
      setError(err.message);
    }
  };

  const handleVoirFacture = async () => {
    try {
      const res = await fetch(`http://localhost:3001/commandes/${formData.idCOM}`);
      if (!res.ok) throw new Error('Erreur récupération facture');
      const data = await res.json();

      // Nettoyer la date dans la facture aussi
      const cleanedData = {
        ...data,
        dateCom: data.dateCom ? data.dateCom.split('T')[0] : data.dateCom
      };

      setFactureData(cleanedData);
      setFactureVisible(true);
    } catch (error) {
      setError(error.message);
    }
  };
  const handlePrintFacture = (action = 'pdf') => {
    if (!factureData) return;
  
    const content = `
      <div style="font-family: Arial, sans-serif; padding: 20px; max-width: 400px; margin: auto; border: 1px solid #ccc;">
        <h3 style="text-align: center;">🧾 Facture Commande #${factureData.idCOM}</h3>
        <p style="font-size: 16px; margin: 5px 0;"><strong>ID Commande :</strong> ${factureData.idCOM}</p>
        <p style="font-size: 16px; margin: 5px 0;"><strong>Code Client :</strong> ${factureData.codeCli || 'N/A'}</p>
        <p style="font-size: 16px; margin: 5px 0;"><strong>Client :</strong> ${factureData.nomCli || 'Inconnu'} ${factureData.prenomCli || ''}</p>
        <p style="font-size: 16px; margin: 5px 0;"><strong>Code Article :</strong> ${factureData.codeArt || 'N/A'}</p>
        <p style="font-size: 16px; margin: 5px 0;"><strong>Article :</strong> ${factureData.nomArt || 'Inconnu'}</p>
        <p style="font-size: 16px; margin: 5px 0;"><strong>Prix unitaire :</strong> ${factureData.prix || 0} €</p>
        <p style="font-size: 16px; margin: 5px 0;"><strong>Quantité :</strong> ${factureData.QteCom || 0}</p>
        <p style="font-size: 16px; margin: 5px 0;"><strong>Date :</strong> ${factureData.dateCom || 'N/A'}</p>
        <p style="font-size: 16px; margin: 5px 0;"><strong>Total :</strong> ${(factureData.QteCom && factureData.prix ? (factureData.QteCom * factureData.prix).toFixed(2) : '0.00')} €</p>
        <p style="text-align: center;">Merci pour votre commande</p>
      </div>
    `;
  
    if (action === 'pdf') {
      // Génération du PDF
      const tempDiv = document.createElement('div');
      tempDiv.style.position = 'absolute';
      tempDiv.style.left = '-9999px';
      tempDiv.innerHTML = content;
      document.body.appendChild(tempDiv);
  
      html2canvas(tempDiv, { scale: 2 }).then((canvas) => {
        const imgData = canvas.toDataURL('image/png');
        const pdf = new jsPDF({
          orientation: 'portrait',
          unit: 'mm',
          format: 'a4',
        });
  
        const imgWidth = 180;
        const pageHeight = pdf.internal.pageSize.height;
        const imgHeight = (canvas.height * imgWidth) / canvas.width;
        const marginTop = (pageHeight - imgHeight) / 2;
  
        pdf.addImage(imgData, 'PNG', 15, marginTop, imgWidth, imgHeight);
  
        const safeIdCOM = String(factureData.idCOM).replace(/[^a-zA-Z0-9]/g, '');
        const fileName = `Facture_Commande_${safeIdCOM}.pdf`;
  
        pdf.save(fileName);
        document.body.removeChild(tempDiv);
      }).catch((error) => {
        console.error('Erreur lors de la génération du PDF :', error);
        document.body.removeChild(tempDiv);
        setError('Erreur lors de la génération du PDF');
      });
    } else if (action === 'print') {
      // Impression classique
      const printWindow = window.open('', '', 'width=600,height=600');
      printWindow.document.write(`
        <html>
          <head>
            <title>Facture Commande #${factureData.idCOM}</title>
            <style>
              body { font-family: Arial, sans-serif; padding: 20px; }
              .facture-box {
                border: 1px solid #ccc;
                padding: 15px;
                max-width: 400px;
                margin: auto;
              }
              h3 { text-align: center; }
              p { font-size: 16px; margin: 5px 0; }
            </style>
          </head>
          <body>
            ${content}
          </body>
        </html>
      `);
      printWindow.document.close();
      printWindow.focus();
      printWindow.onafterprint = () => {
        printWindow.close();
      };
      setTimeout(() => {
        printWindow.print();
      }, 500);
    }
  };

  return (
    <div className="article-form-container">
       <input
          type="number"
          name="idCOM"
          placeholder="ref_commande"
          value={formData.idCOM}
          onChange={handleChange}
          className="input-idCOM"
          style={{ marginRight: '8px', padding: '6px' }}
        />
      <form onSubmit={handleSubmit} className="commande-form">
      <fieldset className="fieldsetstyle">
       
        <input
          name="codeCli"
          placeholder="Code Client"
          value={formData.codeCli}
          onChange={handleChange}
          required
        />
        <input
          name="codeArt"
          placeholder="Code Article"
          value={formData.codeArt}
          onChange={handleChange}
          required
        />
        <input
          type="date"
          name="dateCom"
          placeholder="Date de commande"
          value={formData.dateCom}
          onChange={handleChange}
          required
        />
        <input
          type="number"
          name="QteCom"
          placeholder="Quantité"
          value={formData.QteCom}
          onChange={handleChange}
          required
        />
      </fieldset>
        <div className="button-group">
        <button type="submit">
          {formData.idCOM ? 'Modifier' : 'Ajouter'}
        </button>
      
          {formData.idCOM && (
            <>
              <button type="button" onClick={handleDelete}>Supprimer</button>
              <button type="button" onClick={onCancel}>Annuler</button>
            </>
          )}
          <button type="button" onClick={handleVoirFacture}>Voir facture</button>
        </div>

        {message && <div className="success">{message}</div>}
        {error && <div className="error">{error}</div>}
      </form>

      {factureVisible && factureData && (
  <div className="parent">
    <div className="facture-box">
      <h3>🧾 Facture Commande #{factureData.idCOM}</h3>
      <p><strong>ID Commande :</strong> {factureData.idCOM}</p>
      <p><strong>Code Client :</strong> {factureData.codeCli}</p>
      <p><strong>Client :</strong> {factureData.nomCli} {factureData.prenomCli}</p>
      <p><strong>Code Article :</strong> {factureData.codeArt}</p>
      <p><strong>Article :</strong> {factureData.nomArt}</p>
      <p><strong>Prix unitaire :</strong> {factureData.prix} €</p>
      <p><strong>Quantité :</strong> {factureData.QteCom}</p>
      <p><strong>Date :</strong> {factureData.dateCom}</p>
      <p><strong>Total :</strong> {(factureData.QteCom * factureData.prix).toFixed(2)} €</p>
      <button onClick={handlePrintFacture}>🖨️ Imprimer la facture</button>
    </div>
  </div>
)}
    </div>
  );
};

export default CommandeForm;
